/*
  Manutenção periódica de tópicos em 3 etapas:
  1. Arquivar tópicos dormentes (sem msgs > 7 dias)
  2. Regenerar summaries de tópicos com muitas mensagens novas
  3. Log das operações
*/

const SUPABASE_URL = $env.SUPABASE_URL;
const SUPABASE_KEY = $env.SUPABASE_SERVICE_KEY;
const CLAUDE_KEY   = $env.CLAUDE_API_KEY;

const sbHeaders = {
  'apikey':        SUPABASE_KEY,
  'Authorization': `Bearer ${SUPABASE_KEY}`,
  'Content-Type':  'application/json',
};

const now = new Date();
const h24Ago = new Date(now - 24 * 60 * 60 * 1000).toISOString();
const d7Ago  = new Date(now - 7  * 24 * 60 * 60 * 1000).toISOString();

const results = { archived: 0, summaries_updated: 0, errors: [] };

// ── ETAPA 1: Arquivar tópicos dormentes ──────────────────────
try {
  // Tópicos resolvidos ou open sem mensagem há 7+ dias → archive
  const archiveRes = await $helpers.httpRequest({
    method:  'PATCH',
    url:     `${SUPABASE_URL}/rest/v1/wa_topics` +
             `?last_message_at=lt.${d7Ago}` +
             `&status=in.(open,active,pending_action,resolved)`,
    headers: { ...sbHeaders, 'Prefer': 'return=representation' },
    body:    JSON.stringify({
      status:     'archived',
      updated_at: now.toISOString(),
    }),
  });
  const archived = JSON.parse(archiveRes.body) || [];
  results.archived = Array.isArray(archived) ? archived.length : 0;

  // Inserir eventos de arquivamento
  for (const topic of (Array.isArray(archived) ? archived : [])) {
    try {
      await $helpers.httpRequest({
        method:  'POST',
        url:     `${SUPABASE_URL}/rest/v1/wa_topic_events`,
        headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
        body:    JSON.stringify({
          topic_id:   topic.id,
          event_type: 'archived',
          payload:    { reason: 'dormant_7d', last_message_at: topic.last_message_at },
          created_by: 'system',
        }),
      });
    } catch(e) { /* non-critical */ }
  }
} catch(e) {
  results.errors.push(`archive: ${e.message}`);
}

// ── ETAPA 2: Regenerar summaries ─────────────────────────────
// Tópicos ativos com message_count > 5 que não têm summary ou
// têm summary antigo (updated_at < last_message_at)
try {
  const staleRes = await $helpers.httpRequest({
    method:  'GET',
    url:     `${SUPABASE_URL}/rest/v1/wa_topics` +
             `?status=in.(open,active,pending_action)` +
             `&message_count=gt.4` +
             `&order=last_message_at.desc` +
             `&limit=20` +
             `&select=id,title,group_jid,message_count,summary,updated_at,last_message_at`,
    headers: sbHeaders,
  });
  const staleTopics = JSON.parse(staleRes.body) || [];

  // Filtra tópicos onde summary está desatualizado
  const needsSummary = staleTopics.filter(t => {
    if (!t.summary) return true;
    const updatedAt = new Date(t.updated_at);
    const lastMsg   = new Date(t.last_message_at);
    return lastMsg > updatedAt;
  });

  for (const topic of needsSummary.slice(0, 10)) {
    try {
      // Busca últimas 20 mensagens do tópico
      const msgsRes = await $helpers.httpRequest({
        method:  'GET',
        url:     `${SUPABASE_URL}/rest/v1/wa_messages` +
                 `?topic_id=eq.${topic.id}` +
                 `&order=timestamp.desc` +
                 `&limit=20` +
                 `&select=timestamp,sender_name,is_from_team,content_text`,
        headers: sbHeaders,
      });
      const msgs = (JSON.parse(msgsRes.body) || []).reverse();

      if (msgs.length === 0) continue;

      const msgContext = msgs
        .map(m => `[${m.timestamp}] ${m.is_from_team ? '[EQUIPE]' : '[MENTORADO]'} ${m.sender_name || ''}: ${m.content_text || '[mídia]'}`)
        .join('\n');

      // Gera summary com Claude
      const claudeRes = await $helpers.httpRequest({
        method: 'POST',
        url:    'https://api.anthropic.com/v1/messages',
        headers: {
          'x-api-key':         CLAUDE_KEY,
          'anthropic-version': '2023-06-01',
          'Content-Type':      'application/json',
        },
        body: JSON.stringify({
          model:      'claude-haiku-4-5-20251001',
          max_tokens: 200,
          system:     'Você resume conversas de WhatsApp de mentoria empresarial em 1-3 frases objetivas em português. Foque no que foi discutido, decidido ou pendente.',
          messages: [{
            role:    'user',
            content: `Tópico: "${topic.title}"\n\nMensagens:\n${msgContext}\n\nResuma em 1-3 frases:`,
          }],
        }),
      });

      const claudeData  = JSON.parse(claudeRes.body);
      const summaryText = claudeData.content?.[0]?.text?.trim();

      if (summaryText) {
        await $helpers.httpRequest({
          method:  'PATCH',
          url:     `${SUPABASE_URL}/rest/v1/wa_topics?id=eq.${topic.id}`,
          headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
          body:    JSON.stringify({
            summary:    summaryText,
            updated_at: now.toISOString(),
          }),
        });

        await $helpers.httpRequest({
          method:  'POST',
          url:     `${SUPABASE_URL}/rest/v1/wa_topic_events`,
          headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
          body:    JSON.stringify({
            topic_id:   topic.id,
            event_type: 'ai_reclassified',
            payload:    { action: 'summary_regenerated' },
            created_by: 'ai',
          }),
        });

        results.summaries_updated++;
      }
    } catch(e) {
      results.errors.push(`summary_${topic.id}: ${e.message}`);
    }
  }
} catch(e) {
  results.errors.push(`summaries: ${e.message}`);
}

console.log('[WA Maintenance]', JSON.stringify(results));
return [{ json: { ...results, ran_at: now.toISOString() } }];
